type VL53L1X_Ranging_Sensor
  (Port   : not null HAL.I2C.Any_I2C_Port;
   Timing : not null HAL.Time.Any_Delays) is limited private;

record_types.code:
type Measurement (Status : Ranging_Status := Ok) is record
   case Status is
      when Ok     => Distance : Millimetres;
      when others => null;
   end case;
end record;

